,84,'_wp_page_template','default'),(126,86,'_edit_lock','1722561578:1'),(127,88,'_edit_lock','1722308876:1'),(128,86,'_edit_last','1'),(129,86,'_wp_page_template','default'),(130,82,'_edit_last','1'),(131,82,'_wp_page_template','default'),(132,89,'_edit_lock','1722561574:1'),(133,89,'_edit_last','1'),(134,89,'_wp_page_template','default'),(135,92,'_edit_lock','1722561764:1'),(136,92,'_edit_last','1'),(137,92,'_wp_page_template','default'),(138,95,'_edit_lock','1722561583:1'),(139,95,'_edit_last','1'),(140,95,'_wp_page_template','default'),(141,97,'_edit_lock','1722361501:1'),(142,98,'_edit_lock','1722388940:1'),(144,108,'footnotes',''),(145,118,'_edit_lock','1722561675:1'),(146,3,'_edit_lock','1722427380:1'),(147,121,'_edit_lock','1722561509:1'),(148,123,'_edit_lock','1722561683:1'),(149,3,'_wp_trash_meta_status','publish'),(150,3,'_wp_trash_meta_time','1722427538'),(151,3,'_wp_desired_post_slug','privacy-policy'),(152,118,'_edit_last','1'),(153,118,'_wp_page_template','default'),(154,125,'_edit_lock','1722571838:1'),(155,123,'_edit_last','1'),(156,123,'_wp_page_template','default'),(157,127,'_edit_lock','1722561769:1'),(158,127,'_edit_last','1'),(159,127,'_wp_page_template','default'),(160,121,'_edit_last','1'),(161,121,'_wp_page_template','default'),(162,125,'_edit_last','1'),(163,125,'_wp_page_template','default'),(164,131,'_edit_lock','1722576414:1'),(165,131,'_edit_last','1'),(166,131,'_wp_page_template','default'),(167,140,'_edit_lock','1722571873:1'),(168,141,'footnotes',''),(170,145,'footnotes','');
