--
-- Table structure for table `wp_posts`
--

DROP TABLE IF EXISTS `wp_posts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `wp_posts` (
  `ID` bigint unsigned NOT NULL AUTO_INCREMENT,
  `post_author` bigint unsigned NOT NULL DEFAULT '0',
  `post_date` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_date_gmt` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `post_title` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `post_excerpt` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `post_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT 'publish',
  `comment_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT 'open',
  `ping_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT 'open',
  `post_password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT '',
  `post_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT '',
  `to_ping` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `pinged` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `post_modified` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_modified_gmt` datetime NOT NULL DEFAULT '0000-00-00 00:00:00',
  `post_content_filtered` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `post_parent` bigint unsigned NOT NULL DEFAULT '0',
  `guid` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT '',
  `menu_order` int NOT NULL DEFAULT '0',
  `post_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT 'post',
  `post_mime_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT '',
  `comment_count` bigint NOT NULL DEFAULT '0',
  PRIMARY KEY (`ID`),
  KEY `post_name` (`post_name`(191)),
  KEY `type_status_date` (`post_type`,`post_status`,`post_date`,`ID`),
  KEY `post_parent` (`post_parent`),
  KEY `post_author` (`post_author`)
) ENGINE=InnoDB AUTO_INCREMENT=149 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_520_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `wp_posts`
--

LOCK TABLES `wp_posts` WRITE;
/*!40000 ALTER TABLE `wp_posts` DISABLE KEYS */;
INSERT INTO `wp_posts` VALUES (1,1,'2024-07-26 18:55:06','2024-07-26 18:55:06','<!-- wp:paragraph -->\n<p>Welcome to WordPress. This is your first post. Edit or delete it, then start writing!</p>\n<!-- /wp:paragraph -->','Hello world!','','trash','open','open','','hello-world__trashed','','','2024-07-28 21:50:26','2024-07-28 21:50:26','',0,'http://granjacob.com/blog/?p=1',0,'post','',1),(2,1,'2024-07-26 18:55:06','2024-07-26 18:55:06','<!-- wp:paragraph -->\n<p>In today\'s rapidly evolving technological landscape, efficient and intuitive data management systems are crucial for handling complex data structures. As organizations grow and the volume of data increases exponentially, there arises a need for a robust query language that can cater to diverse data requirements. Enter NEPTUNEQL, a modern query language designed to facilitate seamless interaction with relational data models, providing both simplicity and power to developers and data analysts.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Background and Motivation</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>NEPTUNEQL was conceived with the vision of simplifying complex data interactions while maintaining the flexibility needed to support dynamic and evolving data schemas. Traditional query languages often present challenges when dealing with intricate data relationships and transformations, leading to cumbersome queries and potential performance bottlenecks. NEPTUNEQL aims to address these issues by offering a streamlined syntax and powerful abstraction capabilities.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>The development of NEPTUNEQL is driven by the need to provide a more human-readable and developer-friendly language that bridges the gap between traditional SQL and modern data processing needs. Its design is inspired by the requirements of enterprises that deal with large-scale data and necessitate efficient querying mechanisms to extract valuable insights.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Design Principles</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>The construction of NEPTUNEQL is guided by several core design principles:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Simplicity and Clarity</strong>: NEPTUNEQL syntax is crafted to be intuitive and easy to understand, reducing the learning curve for new users and enabling rapid adoption across teams. The language structure prioritizes clarity, allowing users to express complex queries in a concise manner.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Flexibility and Extensibility</strong>: Recognizing the diverse needs of different industries, NeptuneQL is built to be flexible and extensible. It supports various data types and operations, enabling users to define custom rules and transformations to meet specific business logic requirements.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Powerful Data Manipulation</strong>: NEPTUNEQL is designed to handle complex data relationships and provide advanced data manipulation capabilities. It allows users to define and traverse relationships between entities effortlessly, making it ideal for applications that require sophisticated data interactions.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Scalability and Performance</strong>: As a language built for modern data environments, NeptuneQL emphasizes scalability and performance optimization. Its architecture is optimized to handle large datasets efficiently, ensuring that queries execute quickly even as data volumes grow.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Language Construction</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>The construction of NeptuneQL involves several key components:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Grammar Definition</strong>: NEPTUNEQL\'s grammar is defined using ANTLR, a powerful parser generator that allows the creation of a formal language specification. This grammar defines the syntax and structure of NEPTUNEQL, outlining how queries are parsed and interpreted.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Abstract Syntax Tree (AST)</strong>: Upon parsing a NEPTUNEQL query, an Abstract Syntax Tree (AST) is generated. The AST represents the hierarchical structure of the query, allowing for further analysis and transformation.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Visitor and Listener Patterns</strong>: NEPTUNEQL employs both visitor and listener patterns for traversing the AST. These patterns enable the execution of specific actions as different parts of the query are processed, facilitating tasks such as validation, optimization, and transformation.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Rule-Based Transformation</strong>: NEPTUNEQL supports rule-based transformations, allowing users to define custom rules that modify query behavior. This feature provides flexibility in adapting the language to meet specific application needs.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Use Cases</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>NEPTUNEQL is designed to cater to a wide range of use cases, including but not limited to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Data Integration</strong>: Seamlessly integrating data from various sources and transforming it into a unified view for analysis.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Complex Queries</strong>: Constructing intricate queries involving multiple relationships and transformations with ease.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Custom Reporting</strong>: Generating customized reports that require specific data manipulations and aggregations.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Data Validation</strong>: Implementing data validation rules to ensure data integrity and consistency.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Conclusion</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>NEPTUNEQL represents a significant advancement in query language design, offering a modern, flexible, and powerful tool for managing complex data environments. By prioritizing simplicity, flexibility, and performance, NEPTUNEQL empowers users to harness the full potential of </p>\n<!-- /wp:paragraph -->','NEPTUNEQL','','publish','closed','closed','','neptuneql-com','','','2024-08-01 23:36:12','2024-08-01 23:36:12','',0,'http://granjacob.com/blog/?page_id=2',0,'page','',0),(3,1,'2024-07-26 18:55:06','2024-07-26 18:55:06','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Who we are</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Our website address is: http://granjacob.com/blog.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Comments</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>When visitors leave comments on the site we collect the data shown in the comments form, and also the visitor&#8217;s IP address and browser user agent string to help spam detection.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>An anonymized string created from your email address (also called a hash) may be provided to the Gravatar service to see if you are using it. The Gravatar service privacy policy is available here: https://automattic.com/privacy/. After approval of your comment, your profile picture is visible to the public in the context of your comment.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Media</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you upload images to the website, you should avoid uploading images with embedded location data (EXIF GPS) included. Visitors to the website can download and extract any location data from images on the website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Cookies</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment on our site you may opt-in to saving your name, email address and website in cookies. These are for your convenience so that you do not have to fill in your details again when you leave another comment. These cookies will last for one year.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you visit our login page, we will set a temporary cookie to determine if your browser accepts cookies. This cookie contains no personal data and is discarded when you close your browser.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>When you log in, we will also set up several cookies to save your login information and your screen display choices. Login cookies last for two days, and screen options cookies last for a year. If you select &quot;Remember Me&quot;, your login will persist for two weeks. If you log out of your account, the login cookies will be removed.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you edit or publish an article, an additional cookie will be saved in your browser. This cookie includes no personal data and simply indicates the post ID of the article you just edited. It expires after 1 day.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Embedded content from other websites</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Articles on this site may include embedded content (e.g. videos, images, articles, etc.). Embedded content from other websites behaves in the exact same way as if the visitor has visited the other website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>These websites may collect data about you, use cookies, embed additional third-party tracking, and monitor your interaction with that embedded content, including tracking your interaction with the embedded content if you have an account and are logged in to that website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Who we share your data with</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you request a password reset, your IP address will be included in the reset email.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">How long we retain your data</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment, the comment and its metadata are retained indefinitely. This is so we can recognize and approve any follow-up comments automatically instead of holding them in a moderation queue.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>For users that register on our website (if any), we also store the personal information they provide in their user profile. All users can see, edit, or delete their personal information at any time (except they cannot change their username). Website administrators can also see and edit that information.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">What rights you have over your data</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you have an account on this site, or have left comments, you can request to receive an exported file of the personal data we hold about you, including any data you have provided to us. You can also request that we erase any personal data we hold about you. This does not include any data we are obliged to keep for administrative, legal, or security purposes.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Where your data is sent</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Visitor comments may be checked through an automated spam detection service.</p>\n<!-- /wp:paragraph -->\n','Privacy Policy','','trash','closed','open','','privacy-policy__trashed','','','2024-07-31 12:05:38','2024-07-31 12:05:38','',0,'http://granjacob.com/blog/?page_id=3',0,'page','',0),(4,0,'2024-07-26 18:55:07','2024-07-26 18:55:07','<!-- wp:page-list /-->','Navigation','','publish','closed','closed','','navigation','','','2024-07-26 18:55:07','2024-07-26 18:55:07','',0,'http://granjacob.com/blog/index.php/2024/07/26/navigation/',0,'wp_navigation','',0),(5,1,'2024-07-26 18:55:41','0000-00-00 00:00:00','','Auto Draft','','auto-draft','open','open','','','','','2024-07-26 18:55:41','0000-00-00 00:00:00','',0,'http://granjacob.com/blog/?p=5',0,'post','',0),(6,1,'2024-07-26 19:00:15','2024-07-26 19:00:15','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Introduction</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Welcome to <em>C++ Big Book: A Practical Guide with Samples</em>. This book is designed for anyone who wants to delve into the world of C++, whether you are a complete beginner or someone with prior programming experience looking to enhance your skills. C++ is a powerful and versatile programming language used in various domains, from game development and system programming to scientific computing and financial analysis. With its combination of performance, flexibility, and expressiveness, C++ continues to be a language of choice for many developers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Why C++?</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>C++ offers a unique blend of low-level and high-level features, allowing programmers to write efficient code close to the hardware while maintaining the ability to work with complex data structures and abstractions. The language supports multiple programming paradigms, including procedural, object-oriented, and generic programming, making it an excellent choice for developing a wide range of applications.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">What to Expect</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>In this book, we will explore the core concepts of C++ through practical examples and hands-on exercises. Each chapter focuses on a specific aspect of the language, starting with the basics and gradually advancing to more complex topics. You\'ll find code samples that demonstrate how to apply these concepts in real-world scenarios, along with explanations that clarify the underlying principles.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We will cover topics such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Basics of C++</strong>: Understanding syntax, variables, and data types.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Control Structures</strong>: Using loops and conditionals to control program flow.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Functions and Recursion</strong>: Writing reusable code with functions and exploring recursive solutions.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Object-Oriented Programming</strong>: Designing classes and objects, inheritance, and polymorphism.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Templates and the Standard Template Library (STL)</strong>: Leveraging generic programming and powerful data structures.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Memory Management</strong>: Mastering pointers, dynamic memory allocation, and smart pointers.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Advanced Concepts</strong>: Exploring concurrency, file handling, and exception handling.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">How to Use This Book</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>This book is structured to facilitate learning at your own pace. Each chapter builds upon the previous one, reinforcing key concepts as you progress. Feel free to experiment with the code samples, modify them, and try out different approaches to solidify your understanding. Whether you\'re preparing for a career in software development or simply interested in expanding your programming skills, this book will provide you with the knowledge and confidence to write efficient and robust C++ programs.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Let\'s Get Started</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>C++ is a language that rewards curiosity and persistence. As you embark on this journey, remember that programming is as much about solving problems as it is about writing code. Embrace the challenges, enjoy the learning process, and soon you\'ll find yourself mastering the art of C++ programming. Let\'s dive in and explore the fascinating world of C++ together!</p>\n<!-- /wp:paragraph -->','C++ Big Book','','publish','open','open','','c-big-book','','','2024-07-26 19:58:04','2024-07-26 19:58:04','',0,'http://granjacob.com/blog/?p=6',0,'post','',0),(7,1,'2024-07-26 18:58:42','2024-07-26 18:58:42','{\"version\": 3, \"isGlobalStylesUserThemeJSON\": true }','Custom Styles','','publish','closed','closed','','wp-global-styles-twentytwentyfour','','','2024-07-26 18:58:42','2024-07-26 18:58:42','',0,'http://granjacob.com/blog/index.php/2024/07/26/wp-global-styles-twentytwentyfour/',0,'wp_global_styles','',0),(8,1,'2024-07-26 19:00:15','2024-07-26 19:00:15','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Introduction</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Welcome to <em>C++ Big Book: A Practical Guide with Samples</em>. This book is designed for anyone who wants to delve into the world of C++, whether you are a complete beginner or someone with prior programming experience looking to enhance your skills. C++ is a powerful and versatile programming language used in various domains, from game development and system programming to scientific computing and financial analysis. With its combination of performance, flexibility, and expressiveness, C++ continues to be a language of choice for many developers.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Why C++?</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>C++ offers a unique blend of low-level and high-level features, allowing programmers to write efficient code close to the hardware while maintaining the ability to work with complex data structures and abstractions. The language supports multiple programming paradigms, including procedural, object-oriented, and generic programming, making it an excellent choice for developing a wide range of applications.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">What to Expect</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>In this book, we will explore the core concepts of C++ through practical examples and hands-on exercises. Each chapter focuses on a specific aspect of the language, starting with the basics and gradually advancing to more complex topics. You\'ll find code samples that demonstrate how to apply these concepts in real-world scenarios, along with explanations that clarify the underlying principles.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We will cover topics such as:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Basics of C++</strong>: Understanding syntax, variables, and data types.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Control Structures</strong>: Using loops and conditionals to control program flow.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Functions and Recursion</strong>: Writing reusable code with functions and exploring recursive solutions.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Object-Oriented Programming</strong>: Designing classes and objects, inheritance, and polymorphism.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Templates and the Standard Template Library (STL)</strong>: Leveraging generic programming and powerful data structures.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Memory Management</strong>: Mastering pointers, dynamic memory allocation, and smart pointers.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Advanced Concepts</strong>: Exploring concurrency, file handling, and exception handling.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">How to Use This Book</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>This book is structured to facilitate learning at your own pace. Each chapter builds upon the previous one, reinforcing key concepts as you progress. Feel free to experiment with the code samples, modify them, and try out different approaches to solidify your understanding. Whether you\'re preparing for a career in software development or simply interested in expanding your programming skills, this book will provide you with the knowledge and confidence to write efficient and robust C++ programs.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Let\'s Get Started</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>C++ is a language that rewards curiosity and persistence. As you embark on this journey, remember that programming is as much about solving problems as it is about writing code. Embrace the challenges, enjoy the learning process, and soon you\'ll find yourself mastering the art of C++ programming. Let\'s dive in and explore the fascinating world of C++ together!</p>\n<!-- /wp:paragraph -->','C++ Big Book','','inherit','closed','closed','','6-revision-v1','','','2024-07-26 19:00:15','2024-07-26 19:00:15','',6,'http://granjacob.com/blog/?p=8',0,'revision','',0),(9,1,'2024-07-26 19:10:01','0000-00-00 00:00:00','','Auto Draft','','auto-draft','open','open','','','','','2024-07-26 19:10:01','0000-00-00 00:00:00','',0,'http://granjacob.com/blog/?p=9',0,'post','',0),(10,1,'2024-07-26 19:18:59','2024-07-26 19:18:59','<!-- wp:paragraph -->\n<p>In today\'s rapidly evolving technological landscape, efficient and intuitive data management systems are crucial for handling complex data structures. As organizations grow and the volume of data increases exponentially, there arises a need for a robust query language that can cater to diverse data requirements. Enter NEPTUNEQL, a modern query language designed to facilitate seamless interaction with relational data models, providing both simplicity and power to developers and data analysts.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Background and Motivation</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>NEPTUNEQL was conceived with the vision of simplifying complex data interactions while maintaining the flexibility needed to support dynamic and evolving data schemas. Traditional query languages often present challenges when dealing with intricate data relationships and transformations, leading to cumbersome queries and potential performance bottlenecks. NEPTUNEQL aims to address these issues by offering a streamlined syntax and powerful abstraction capabilities.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>The development of NEPTUNEQL is driven by the need to provide a more human-readable and developer-friendly language that bridges the gap between traditional SQL and modern data processing needs. Its design is inspired by the requirements of enterprises that deal with large-scale data and necessitate efficient querying mechanisms to extract valuable insights.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Design Principles</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>The construction of NEPTUNEQL is guided by several core design principles:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Simplicity and Clarity</strong>: NEPTUNEQL syntax is crafted to be intuitive and easy to understand, reducing the learning curve for new users and enabling rapid adoption across teams. The language structure prioritizes clarity, allowing users to express complex queries in a concise manner.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Flexibility and Extensibility</strong>: Recognizing the diverse needs of different industries, NeptuneQL is built to be flexible and extensible. It supports various data types and operations, enabling users to define custom rules and transformations to meet specific business logic requirements.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Powerful Data Manipulation</strong>: NEPTUNEQL is designed to handle complex data relationships and provide advanced data manipulation capabilities. It allows users to define and traverse relationships between entities effortlessly, making it ideal for applications that require sophisticated data interactions.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Scalability and Performance</strong>: As a language built for modern data environments, NeptuneQL emphasizes scalability and performance optimization. Its architecture is optimized to handle large datasets efficiently, ensuring that queries execute quickly even as data volumes grow.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Language Construction</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>The construction of NeptuneQL involves several key components:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Grammar Definition</strong>: NEPTUNEQL\'s grammar is defined using ANTLR, a powerful parser generator that allows the creation of a formal language specification. This grammar defines the syntax and structure of NEPTUNEQL, outlining how queries are parsed and interpreted.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Abstract Syntax Tree (AST)</strong>: Upon parsing a NEPTUNEQL query, an Abstract Syntax Tree (AST) is generated. The AST represents the hierarchical structure of the query, allowing for further analysis and transformation.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Visitor and Listener Patterns</strong>: NEPTUNEQL employs both visitor and listener patterns for traversing the AST. These patterns enable the execution of specific actions as different parts of the query are processed, facilitating tasks such as validation, optimization, and transformation.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Rule-Based Transformation</strong>: NEPTUNEQL supports rule-based transformations, allowing users to define custom rules that modify query behavior. This feature provides flexibility in adapting the language to meet specific application needs.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Use Cases</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>NEPTUNEQL is designed to cater to a wide range of use cases, including but not limited to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Data Integration</strong>: Seamlessly integrating data from various sources and transforming it into a unified view for analysis.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Complex Queries</strong>: Constructing intricate queries involving multiple relationships and transformations with ease.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Custom Reporting</strong>: Generating customized reports that require specific data manipulations and aggregations.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Data Validation</strong>: Implementing data validation rules to ensure data integrity and consistency.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Conclusion</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>NEPTUNEQL represents a significant advancement in query language design, offering a modern, flexible, and powerful tool for managing complex data environments. By prioritizing simplicity, flexibility, and performance, NEPTUNEQL empowers users to harness the full potential of their data, driving innovation and insights across organizations. As data continues to play a central role in decision-making and strategy, NEPTUNEQL stands poised to become an essential component of the modern data stack.</p>\n<!-- /wp:paragraph -->','NEPTUNEQL','','publish','open','open','','neptuneql','','','2024-07-26 19:18:59','2024-07-26 19:18:59','',0,'http://granjacob.com/blog/?p=10',0,'post','',0),(11,1,'2024-07-26 19:18:59','2024-07-26 19:18:59','<!-- wp:paragraph -->\n<p>In today\'s rapidly evolving technological landscape, efficient and intuitive data management systems are crucial for handling complex data structures. As organizations grow and the volume of data increases exponentially, there arises a need for a robust query language that can cater to diverse data requirements. Enter NEPTUNEQL, a modern query language designed to facilitate seamless interaction with relational data models, providing both simplicity and power to developers and data analysts.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Background and Motivation</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>NEPTUNEQL was conceived with the vision of simplifying complex data interactions while maintaining the flexibility needed to support dynamic and evolving data schemas. Traditional query languages often present challenges when dealing with intricate data relationships and transformations, leading to cumbersome queries and potential performance bottlenecks. NEPTUNEQL aims to address these issues by offering a streamlined syntax and powerful abstraction capabilities.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>The development of NEPTUNEQL is driven by the need to provide a more human-readable and developer-friendly language that bridges the gap between traditional SQL and modern data processing needs. Its design is inspired by the requirements of enterprises that deal with large-scale data and necessitate efficient querying mechanisms to extract valuable insights.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Design Principles</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>The construction of NEPTUNEQL is guided by several core design principles:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Simplicity and Clarity</strong>: NEPTUNEQL syntax is crafted to be intuitive and easy to understand, reducing the learning curve for new users and enabling rapid adoption across teams. The language structure prioritizes clarity, allowing users to express complex queries in a concise manner.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Flexibility and Extensibility</strong>: Recognizing the diverse needs of different industries, NeptuneQL is built to be flexible and extensible. It supports various data types and operations, enabling users to define custom rules and transformations to meet specific business logic requirements.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Powerful Data Manipulation</strong>: NEPTUNEQL is designed to handle complex data relationships and provide advanced data manipulation capabilities. It allows users to define and traverse relationships between entities effortlessly, making it ideal for applications that require sophisticated data interactions.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Scalability and Performance</strong>: As a language built for modern data environments, NeptuneQL emphasizes scalability and performance optimization. Its architecture is optimized to handle large datasets efficiently, ensuring that queries execute quickly even as data volumes grow.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Language Construction</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>The construction of NeptuneQL involves several key components:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Grammar Definition</strong>: NEPTUNEQL\'s grammar is defined using ANTLR, a powerful parser generator that allows the creation of a formal language specification. This grammar defines the syntax and structure of NEPTUNEQL, outlining how queries are parsed and interpreted.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Abstract Syntax Tree (AST)</strong>: Upon parsing a NEPTUNEQL query, an Abstract Syntax Tree (AST) is generated. The AST represents the hierarchical structure of the query, allowing for further analysis and transformation.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Visitor and Listener Patterns</strong>: NEPTUNEQL employs both visitor and listener patterns for traversing the AST. These patterns enable the execution of specific actions as different parts of the query are processed, facilitating tasks such as validation, optimization, and transformation.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Rule-Based Transformation</strong>: NEPTUNEQL supports rule-based transformations, allowing users to define custom rules that modify query behavior. This feature provides flexibility in adapting the language to meet specific application needs.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Use Cases</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>NEPTUNEQL is designed to cater to a wide range of use cases, including but not limited to:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Data Integration</strong>: Seamlessly integrating data from various sources and transforming it into a unified view for analysis.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Complex Queries</strong>: Constructing intricate queries involving multiple relationships and transformations with ease.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Custom Reporting</strong>: Generating customized reports that require specific data manipulations and aggregations.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Data Validation</strong>: Implementing data validation rules to ensure data integrity and consistency.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Conclusion</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>NEPTUNEQL represents a significant advancement in query language design, offering a modern, flexible, and powerful tool for managing complex data environments. By prioritizing simplicity, flexibility, and performance, NEPTUNEQL empowers users to harness the full potential of their data, driving innovation and insights across organizations. As data continues to play a central role in decision-making and strategy, NEPTUNEQL stands poised to become an essential component of the modern data stack.</p>\n<!-- /wp:paragraph -->','NEPTUNEQL','','inherit','closed','closed','','10-revision-v1','','','2024-07-26 19:18:59','2024-07-26 19:18:59','',10,'http://granjacob.com/blog/?p=11',0,'revision','',0),(12,1,'2024-07-26 19:27:41','2024-07-26 19:27:41','{\"version\": 3, \"isGlobalStylesUserThemeJSON\": true }','Custom Styles','','publish','closed','closed','','wp-global-styles-dualtone','','','2024-07-26 19:27:41','2024-07-26 19:27:41','',0,'http://granjacob.com/blog/index.php/2024/07/26/wp-global-styles-dualtone/',0,'wp_global_styles','',0),(13,1,'2024-07-26 20:06:14','2024-07-26 20:06:14','<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Word</th><th>Past</th><th>Present</th><th>Future</th></tr></thead><tbody><tr><td>a</td><td>-</td><td>-</td><td>-</td></tr><tr><td>abandon</td><td>abandoned</td><td>abandon</td><td>will abandon</td></tr><tr><td>ability</td><td>-</td><td>-</td><td>-</td></tr><tr><td>able</td><td>was able</td><td>am/are/is able</td><td>will be able</td></tr><tr><td>abortion</td><td>-</td><td>-</td><td>-</td></tr><tr><td>ab