 wp:list-item -->\n<li>They abase themselves when they conform to peer pressure.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Past Tense Phrases:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>I abased myself by accepting an unfair offer.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>You abased yourself during the meeting yesterday.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>He abased himself in front of the crowd last week.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>She abased herself to please others in her previous job.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>We abased ourselves by compromising our values.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>They abased themselves by giving in to the opposition.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Future Tense Phrases:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>I will not abase myself for anyone\'s approval.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>You will abase yourself if you let them take advantage of you.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>He will abase himself to avoid conflict, although he shouldn’t.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>She will abase herself if she continues to doubt her worth.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>We will not abase ourselves, as we value our integrity.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>They will abase themselves if they prioritize others\' opinions over their own.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Usage with Adverbs of Frequency:</h3>